+{% extends "base.html" %}
+
+{% block announce %}
+<style>
+  .md-banner {
+    background-color: #fff3cd !important;
+    color: #856404 !important;
+    display: block !important;
+  }
+  .md-banner a {
+    color: #d97706;
+    font-weight: bold;
+  }
+  [data-md-color-scheme="slate"] .md-banner {
+    background-color: #333 !important;
+    color: #ddd !important;
+  }
+  [data-md-color-scheme="slate"] .md-banner a {
+    color: #ffa500;
+  }
+</style>
